    /*
     * Última posición conocida — se actualiza en scan() para que
     * los errores semánticos generados en acciones tengan la línea
     * real del token que los disparó, en lugar de 0,0.
     */
    public static int currentLine = 1;
    public static int currentCol  = 1;

    /**
     * Sobreescribimos scan() para interceptar cada token y registrar
     * su posición antes de que el parser lo consuma.
     */
    @Override
    public Symbol scan() throws Exception {
        Symbol s = super.scan();
        if (s != null) {
            /* s.left es yyline (0-based desde JFlex), +1 → 1-based */
            currentLine = s.left  + 1;
            currentCol  = s.right + 1;
        }
        return s;
    }

    @Override
    public void syntax_error(Symbol s) {
        /*
         * s es el token que el parser NO pudo consumir.
         * Mostramos línea/columna de ESE token (el conflictivo),
         * más un mensaje que describe qué se esperaba en ese contexto.
         */
        int    lin    = s.left  + 1;
        int    col    = s.right + 1;
        String lexema = (s.value != null && !s.value.toString().isEmpty())
                        ? s.value.toString() : tokenNombre(s.sym);

        String msg;
        if (s.sym == sym.EOF) {
            msg = "Fin de archivo inesperado — verifique que todos los bloques " +
                  "{ } [ ] estén cerrados correctamente.";
        } else {
            switch (s.sym) {
                case sym.PUNTOCOMA:         msg = "Se esperaba ';' pero se encontró '" + lexema + "'"; break;
                case sym.CORCHETE_CIERRA:   msg = "Se esperaba ']' pero se encontró '" + lexema + "'"; break;
                case sym.CORCHETE_ABRE:     msg = "Se esperaba '[' pero se encontró '" + lexema + "'"; break;
                case sym.LLAVE_CIERRA:      msg = "Se esperaba '}' pero se encontró '" + lexema + "'"; break;
                case sym.LLAVE_ABRE:        msg = "Se esperaba '{' pero se encontró '" + lexema + "'"; break;
                case sym.COMA:              msg = "Se esperaba ',' pero se encontró '" + lexema + "'"; break;
                case sym.PARENTESIS_CIERRA: msg = "Se esperaba ')' pero se encontró '" + lexema + "'"; break;
                case sym.PARENTESIS_ABRE:   msg = "Se esperaba '(' pero se encontró '" + lexema + "'"; break;
                case sym.DOSPUNTOS:         msg = "Se esperaba ':' pero se encontró '" + lexema + "'"; break;
                case sym.IGUAL:             msg = "Se esperaba '=' pero se encontró '" + lexema + "'"; break;
                default:
                    msg = "Token inesperado '" + lexema + "'";
            }
        }
        listaErrores.add(new Token(lexema, lin, col, "Sintáctico", msg));
    }

    /** Convierte el código numérico de un terminal a su nombre legible. */
    private String tokenNombre(int sym_code) {
        switch (sym_code) {
            case sym.VARIABLENUMBER:    return "number";
            case sym.VARIABLESTRING:    return "string";
            case sym.SPECIAL:           return "special";
            case sym.OPENQUESTION:      return "OPEN_QUESTION";
            case sym.DROPQUESTION:      return "DROP_QUESTION";
            case sym.SELECTQUESTION:    return "SELECT_QUESTION";
            case sym.MULTIPLEQUESTION:  return "MULTIPLE_QUESTION";
            case sym.SECTION:           return "SECTION";
            case sym.TABLE:             return "TABLE";
            case sym.TEXT:              return "TEXT";
            case sym.DRAW:              return "draw";
            case sym.IF:                return "IF";
            case sym.ELSE:              return "ELSE";
            case sym.WHILE:             return "WHILE";
            case sym.DO:                return "DO";
            case sym.FOR:               return "FOR";
            case sym.IN:                return "in";
            case sym.SUMA:              return "+";
            case sym.RESTA:             return "-";
            case sym.MULTI:             return "*";
            case sym.DIVISION:          return "/";
            case sym.IGUAL:             return "=";
            case sym.IGUALIGUAL:        return "==";
            case sym.DIFERENTE:         return "!!";
            case sym.MAYOR:             return ">";
            case sym.MENOR:             return "<";
            case sym.MAYORIGUAL:        return ">=";
            case sym.MENORIGUAL:        return "<=";
            case sym.AND:               return "&&";
            case sym.OR:                return "||";
            case sym.NOT:               return "~";
            case sym.CORCHETE_ABRE:     return "[";
            case sym.CORCHETE_CIERRA:   return "]";
            case sym.LLAVE_ABRE:        return "{";
            case sym.LLAVE_CIERRA:      return "}";
            case sym.PARENTESIS_ABRE:   return "(";
            case sym.PARENTESIS_CIERRA: return ")";
            case sym.COMA:              return ",";
            case sym.DOSPUNTOS:         return ":";
            case sym.PUNTOCOMA:         return ";";
            case sym.PUNTO:             return ".";
            case sym.RANGO:             return "..";
            case sym.INTERROGACION:     return "?";
            case sym.ENTERO:            return "<número entero>";
            case sym.DECIMAL:           return "<número decimal>";
            case sym.CADENA:            return "<cadena>";
            case sym.VARIABLE:          return "<identificador>";
            case sym.HEXCOLOR:          return "<color hex>";
            case sym.EOF:               return "<fin de archivo>";
            default:                    return "<token " + sym_code + ">";
        }
    }

    @Override
    public void report_error(String message, Object info) {
        if (info instanceof Symbol) {
            Symbol s = (Symbol) info;
            int lin = s.left  + 1;
            int col = s.right + 1;
            String lexema = s.value != null ? s.value.toString() : "EOF";
            listaErrores.add(new Token(lexema, lin, col, "Sintáctico", message));
        }
    }

    @Override
    public void report_fatal_error(String message, Object info) {
        report_error(message, info);
    }

    public void ejecutarInstrucciones(ArrayList<Object> lista) {
        if (lista == null) return;
        for (Object o : lista) {
            if (o == null) continue;
            if (o instanceof AnalizadorSemantico.AsignacionPendiente) {
                ((AnalizadorSemantico.AsignacionPendiente) o).ejecutar(semantico);
            } else {
                ResultParser.currentForm.addElement(o);
            }
        }
    }

    public static boolean contieneComodin(Object value) {
        if (value == null) return false;

        if (value instanceof String) {
            String s = (String) value;
            if (s.contains("?")) return true;
            if (s.matches("[\\d.]+[+\\-*/%^]\\?")) return true;
            if (s.matches("\\?[+\\-*/%^][\\d.]+")) return true;
        }

        if (value instanceof List) {
            List<?> list = (List<?>) value;
            for (Object item : list) {
                if (contieneComodin(item)) return true;
            }
        }

        return false;
    }

     public static Object evaluarArgumento(Object arg) {
            if (arg == null) return null;

            System.out.println("[evaluarArgumento] Recibido: " + arg +
                             " (tipo: " + arg.getClass().getSimpleName() + ")");

            if (arg instanceof String) {
                String str = (String) arg;

                if (str.matches(".*[+\\-*/%^].*") && !str.contains("?")) {
                    try {
                        double result = semantico.evaluar(str);
                        System.out.println("evaluarArgumento: Expresión evaluada: " + str + " = " + result);
                        return result;
                    } catch (Exception e) {
                        System.out.println("evaluarArgumento: Error evaluando expresión: " + e.getMessage());
                    }
                }

                try {
                    double num = Double.parseDouble(str);
                    return num;
                } catch (NumberFormatException e) {
                }
            }

            if (arg instanceof Number) {
                return arg;
            }

            return arg;
        }


